#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (!s || !out)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* detect sign */
    int negative = 0;
    if (*s == '-') {
        negative = 1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (*s == '\0' || !isdigit((unsigned char)*s))
        return 0;

    /* parse digits, checking overflow/underflow */
    int32_t limit = negative ? -(int32_t)INT32_MAX : INT32_MAX;
    int32_t rem   = negative ?  (int32_t)INT32_MIN : -(int32_t)INT32_MAX;
    int32_t acc   = 0;

    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';
        if (acc > limit || (acc == limit && digit > -rem))
            return 0;
        acc = acc * 10 + digit;
        s++;
    }

    /* skip trailing whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s != '\0')
        return 0;

    if (negative)
        acc = -acc;

    *out = acc;
    return 1;
}

